import { AbsoluteFill, continueRender, delayRender } from "@vendor/remotion";
import type React from "react";
import { useEffect, useState } from "react";
import { IngestedData } from "./sections/ingested-data";
import { LogoAnimation } from "./sections/logo-animation";
import { StreamEvents } from "./sections/stream-events";
import { ensureFontsLoaded } from "./shared/fonts";
import { GridLines } from "./shared/grid-lines";
import { SECTION_TIMING } from "./shared/timing";

/**
 * 3×3 isometric grid layout.
 *
 *   Cell (col,row)     Contents
 *   (0,0)  (1,0)  (2,0)     ×  StreamEvents  ×
 *   (0,1)  (1,1)  (2,1)     ×  Logo           ×
 *   (0,2)  (1,2)  (2,2)     [--- Search (2-wide, centered) ---]
 *
 *   Cell: 512 × 512   Plane: 1536 × 1536
 */
const CELL_W = 512;
const CELL_H = 512;
const PLANE_WIDTH = CELL_W * 3;
const PLANE_HEIGHT = CELL_H * 3;
const PLANE_SCALE = 1.1;
const ISO_TILT_DEGREES = 54.7356;
const ISO_ROTATE_Z_DEGREES = -45;

export const LandingHero: React.FC = () => {
  const [handle] = useState(() => delayRender("Loading fonts"));

  useEffect(() => {
    void ensureFontsLoaded()
      .then(() => continueRender(handle))
      .catch((err: unknown) => {
        console.error("Font loading failed:", err);
        continueRender(handle);
      });
  }, [handle]);

  return (
    <AbsoluteFill className="bg-background">
      {/* Centering wrapper — keeps translate separate from 3D context */}
      <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2">
        <div
          className="origin-center"
          style={{
            width: PLANE_WIDTH,
            height: PLANE_HEIGHT,
            transform: `
            rotateX(${ISO_TILT_DEGREES}deg)
            rotateZ(${ISO_ROTATE_Z_DEGREES}deg)
            scale(${PLANE_SCALE})
          `,
            transformStyle: "preserve-3d",
          }}
        >
          <GridLines
            cellH={CELL_H}
            cellW={CELL_W}
            planeH={PLANE_HEIGHT}
            planeW={PLANE_WIDTH}
            startFrame={SECTION_TIMING.GRID.start}
          />

          <StreamEvents />
          <IngestedData />
        </div>
      </div>

      {/* LogoAnimation uses its own math-based iso projection — render outside CSS 3D plane */}
      <LogoAnimation />
    </AbsoluteFill>
  );
};

import type { SpringConfig } from "@vendor/remotion";

export const SPRING_CONFIGS = {
  SMOOTH: { damping: 200 } satisfies Partial<SpringConfig>,
  GENTLE: { damping: 300 } satisfies Partial<SpringConfig>,
  SNAPPY: { damping: 20, stiffness: 200 } satisfies Partial<SpringConfig>,
} as const;

/** Shared animation durations (in frames) */
export const MOTION_DURATION = {
  GRID_DRAW: 44,
  GRID_OPACITY: 22,
  CARD_ENTRANCE: 36,
  ROW_ENTRANCE: 36,
  LOGO_MARK_ENTRANCE: 28,
  LOGO_ROTATION: 240,
} as const;

/** Frame offsets for each section's entrance */
export const SECTION_TIMING = {
  /** Grid lines draw in */
  GRID: { start: -MOTION_DURATION.GRID_DRAW },
  /** Section 1: Stream events card — cell (1,0) */
  STREAM_EVENTS: { start: 6, entrance: 6 },
  /** Section 2: Logo / engine — cell (1,1) */
  LOGO: { start: 48, entrance: 48 },
  /** Bottom row — cells (0,2), (1,2), (2,2) */
  BOTTOM_LEFT: { start: 78, entrance: 78 },
  BOTTOM_CENTER: { start: 88, entrance: 88 },
  BOTTOM_RIGHT: { start: 98, entrance: 98 },
} as const;

/** Beam animation — energy pulse traveling down grid columns to IngestedData */
export const BEAM_TIMING = {
  /** Frame when beams start traveling */
  START: 50,
  /** How many frames the beam takes to travel */
  TRAVEL_FRAMES: 50,
  /** Frame when beams arrive at IngestedData intersection (START + TRAVEL_FRAMES) */
  ARRIVAL: 100,
} as const;

/** Stagger delay between rows appearing inside cards */
export const ROW_STAGGER = {
  STREAM_EVENTS: 3,
  INGESTED_DATA: 24,
