5	import {
6	  renderMedia,
7	  renderStill,
8	  selectComposition,
9	} from "@vendor/remotion/renderer";
10	import { getStills, getVideos, MANIFEST } from "./manifest";
11	import { enableCssLoaders } from "./webpack-override";
12	
13	const __dirname = path.dirname(fileURLToPath(import.meta.url));
14	const ROOT = path.resolve(__dirname, "../../.."); // monorepo root
15	
16	/** Resolve a manifest dest path to an absolute path */
17	function resolveDest(dest: string, filename: string): string {
18	  return path.resolve(ROOT, dest, filename);
19	}
20	
21	/** Pack multiple PNG buffers into a single .ico file */
22	function buildIco(pngs: Buffer[]): Buffer {
23	  const HEADER = 6;
24	  const ENTRY = 16;
25	  const headerBuf = Buffer.alloc(HEADER + ENTRY * pngs.length);
26	  headerBuf.writeUInt16LE(0, 0);
27	  headerBuf.writeUInt16LE(1, 2);
28	  headerBuf.writeUInt16LE(pngs.length, 4);
29	
30	  let dataOffset = HEADER + ENTRY * pngs.length;
31	  for (let i = 0; i < pngs.length; i++) {
32	    const png = pngs[i]!;
33	    const w = png.readUInt32BE(16);
34	    const h = png.readUInt32BE(20);
35	    const off = HEADER + ENTRY * i;
36	    headerBuf.writeUInt8(w >= 256 ? 0 : w, off);
37	    headerBuf.writeUInt8(h >= 256 ? 0 : h, off + 1);
38	    headerBuf.writeUInt8(0, off + 2);
39	    headerBuf.writeUInt8(0, off + 3);
40	    headerBuf.writeUInt16LE(1, off + 4);
41	    headerBuf.writeUInt16LE(32, off + 6);
42	    headerBuf.writeUInt32LE(png.length, off + 8);
43	    headerBuf.writeUInt32LE(dataOffset, off + 12);
44	    dataOffset += png.length;
45	  }
46	  return Buffer.concat([headerBuf, ...pngs]);
47	}
48	
49	/** Copy a rendered file to all its declared destinations */
50	async function distribute(
51	  sourcePath: string,
52	  outputs: Array<{ dest: string; filename?: string }>,
53	  defaultFilename: string
54	) {
55	  for (const output of outputs) {
56	    const destPath = resolveDest(
57	      output.dest,
58	      output.filename ?? defaultFilename
59	    );
60	    await fs.mkdir(path.dirname(destPath), { recursive: true });
61	    if (destPath !== sourcePath) {
62	      await fs.copyFile(sourcePath, destPath);
63	    }
64	  }
65	}
66	
67	// ── Filter support ───────────────────────────────────────────────────
68	// Usage: npx tsx src/render.ts [--only stills|video|all] [--id composition-id]
69	const args = process.argv.slice(2);
70	const onlyFlag = args.includes("--only")
71	  ? args[args.indexOf("--only") + 1]
72	  : "all";
73	const idFlag = args.includes("--id")
74	  ? args[args.indexOf("--id") + 1]
75	  : undefined;
76	
77	async function main() {
78	  const startedAt = Date.now();
79	  const entryPoint = path.resolve(__dirname, "index.ts");
80	  const tmpDir = path.resolve(__dirname, "../.cache/render");
81	  await fs.mkdir(tmpDir, { recursive: true });
82	
83	  console.log("Bundling compositions...");
84	  const bundled = await bundle({
85	    entryPoint,
86	    publicDir: path.resolve(__dirname, "../public"),
87	    webpackOverride: enableCssLoaders,
88	  });
89	
90	  // ── Render video compositions ──────────────────────────────────
91	  if (onlyFlag === "all" || onlyFlag === "video") {
92	    for (const [id, entry] of getVideos()) {
93	      if (idFlag && idFlag !== id) {
94	        continue;
95	      }
96	
97	      const composition = await selectComposition({ serveUrl: bundled, id });
98	
99	      for (const output of entry.outputs) {
100	        const filename = output.filename ?? `${id}.${output.format}`;
101	
102	        if (output.frame !== undefined) {
103	          // Still frame extraction from video
104	          const tmpPath = path.join(tmpDir, filename);
105	          console.log(`Rendering ${id} poster (frame ${output.frame})...`);
106	          await renderStill({
107	            composition,
108	            serveUrl: bundled,
109	            output: tmpPath,
110	            frame: output.frame,
111	            imageFormat: output.format as "webp" | "png",
112	            scale: output.scale ?? 1,
113	            overwrite: true,
114	          });
115	          await distribute(tmpPath, [output], filename);
116	          console.log(`  ✔ ${filename} → ${output.dest}`);
117	        } else {
118	          // Full video render
